const App: React.FC = () => {
  // Inicializa a tabela de frete do Mercado Livre ao carregar a aplicação
  useEffect(() => {
    inicializarTabelaFrete().catch(err => {
      console.warn('[App] Erro ao inicializar tabela de frete:', err);
    });
  }, []);

  return (
    <Router>
      <div className="app-shell">
        <Navigation />
        <main className="content-area">
          <Routes>
            <Route path="/login" element={<LoginPage />} />
            <Route path="/shopee" element={<ProtectedRoute><ShopeePage /></ProtectedRoute>} />
            <Route path="/shopee/lote" element={<ProtectedRoute><ShopeeLotePage /></ProtectedRoute>} />
            <Route path="/catalogo" element={<ProtectedRoute><CatalogPage /></ProtectedRoute>} />
            <Route path="/meli" element={<ProtectedRoute><MeliPage /></ProtectedRoute>} />
            <Route path="/" element={<Navigate to="/shopee" replace />} />
          </Routes>
        </main>
        <footer className="main-footer">
          <div className="container">
            <div className="footer-content">
              <div className="footer-brand">
                <img src="/lcg-logo.svg" alt="LCG Logo" className="footer-logo" />
              </div>

              <div className="footer-nav">
                <Link to="/shopee" className="footer-link">Calculadora Shopee</Link>
                <span className="footer-divider">|</span>
                <Link to="/meli" className="footer-link">Calculadora Mercado Livre</Link>
                <span className="footer-divider">|</span>
                <Link to="/catalogo" className="footer-link">Catálogo de Produtos</Link>
              </div>

              <p className="footer-copyright">
                © {new Date().getFullYear()} Calculadora LCG. Todos os direitos reservados. | Versão {APP_VERSION}
              </p>
            </div>
          </div>
        </footer>
      </div>
    </Router>
  );
};

export default App;
